-- Updated [PT/ST/OT] multiple procedure Rule as per the hospital feedback by Naveen Abboju 05.30.2025
-- Updtaed Modifier FB, as per Ricardo's Feedback for Drugs by Naveen Abboju 07.10.2025  
-- Updated 2025 contract rates by Naveen Abboju 08.11.2025
-- Fixed Lithotripsy Logica and cardiac cath 9.04.2025 SC

USE [COL]

IF OBJECT_ID('tempdb..#Step1') IS NOT NULL DROP TABLE #Step1
IF OBJECT_ID('tempdb..#Step1_Charges') IS NOT NULL DROP TABLE #Step1_Charges
IF OBJECT_ID('tempdb..#Step2') IS NOT NULL DROP TABLE #Step2
IF OBJECT_ID('tempdb..#Step3') IS NOT NULL DROP TABLE #Step3
IF OBJECT_ID('tempdb..#Step3Bundle') IS NOT NULL DROP TABLE #Step3Bundle
IF OBJECT_ID('tempdb..#Step3_1') IS NOT NULL DROP TABLE #Step3_1
IF OBJECT_ID('tempdb..#Step3_2') IS NOT NULL DROP TABLE #Step3_2
IF OBJECT_ID('tempdb..#Step4') IS NOT NULL DROP TABLE #Step4
IF OBJECT_ID('tempdb..#Step5') IS NOT NULL DROP TABLE #Step5
IF OBJECT_ID('tempdb..#Step6') IS NOT NULL DROP TABLE #Step6
IF OBJECT_ID('tempdb..#Step7') IS NOT NULL DROP TABLE #Step7
IF OBJECT_ID('tempdb..#StepFinal') IS NOT NULL DROP TABLE #StepFinal
-- *** PRICE BREAKDOWN TABLES (added for auditor visibility) ***
IF OBJECT_ID('tempdb..#bRanked')       IS NOT NULL DROP TABLE #bRanked
IF OBJECT_ID('tempdb..#bSlots')        IS NOT NULL DROP TABLE #bSlots
IF OBJECT_ID('tempdb..#LineBreakdown') IS NOT NULL DROP TABLE #LineBreakdown

--***********************************************************************************************************************************************************************************************************************************************************************************************************
Select x.[EncounterID], [TypeOfBill], [RevenueCode], [ProcedureCode], [Payer01Name], [Payer01Code], y.[Contract], y.[Plan], p.[AuditorName], p.[employee_type], p.[audit_by], p.[audit_date]

INTO #Step1
FROM [COL].[Data].[Charges] as x

	LEFT JOIN [COL].[Data].[Demo] as y on x.EncounterID = y.EncounterID
	LEFT JOIN [PRS].[dbo].[PRS_Data] as p on x.[EncounterID] = p.[patient_id_real]
	LEFT JOIN [PRS].[dbo].Underpayments AS p1 ON p.[patient_id_real] = p1.[patient_id_real]

where TypeOfBill = 'Outpatient'

	and Payer01Name in (
		'AETNA LUMINARE CORESOURCE',
		'AETNA LUMINARE STARMARK',
		'AETNA ALLIED BENEFIT SYSTEMS',
		'AETNA CHRISTIAN BROTHER EMPLOYEE BENEFIT',
		'AETNA TRUSTMARK CORESOURCE',
		'AETNA TRUSTMARK IOWA',
		'AETNA TRUSTMARK KANSAS',
		'AETNA TRUSTMARK STARMARK',
		'BOON-CHAPMAN AETNA SIGNATURE',
		'NIPPON AETNA',
		'ROCKEFELLER UNIVERSITY',
		'WEBTPA AETNA SIGNATURE')

	and SubscriberID not like ('101%') AND [SubscriberID] NOT LIKE ('MEB%')

	and p.[hospital] = 'NYP Columbia' and p.[audit_by] is null and p.[audit_date] is null and p.[employee_type] = 'Analyst'
	--    and (p.account_status = 'HAA' and p1.close_date is null and p1.status not in ('Write Off Requested', 'Payor said paid'))

	--and y.[AGE] < 65

	AND x.[ServiceDateFrom] < '2026-01-01'

--  and procedurecode = '50590'

Group by x.[EncounterID], [TypeOfBill], [RevenueCode], [ProcedureCode], [Payer01Name], [Payer01Code], y.[Contract], y.[Plan], p.[AuditorName], p.[employee_type], p.[audit_by], p.[audit_date]

--***********************************************************************************************************************************************************************************************************************************************************************************************************
Select x.*
	
	, IIF(SUBSTRING(ProcedureCode, 1, 1) LIKE '[A-Za-z]%' or SUBSTRING(ProcedureCode, LEN(ProcedureCode), 1) LIKE '[A-Za-z]%' or ProcedureCode = '', 0, CAST(ProcedureCode as numeric)) as ProcedureCodeNumeric

INTO #Step1_Charges
FROM [COL].[Data].[Charges] as x

where x.[EncounterID] in (Select [EncounterID]
from #Step1);

--***********************************************************************************************************************************************************************************************************************************************************************************************************
WITH
	CTE
	AS
	(
		SELECT M1.[HCPCS], M1.[MOD], M1.[StartDate], M1.[EndDate], M1.[RATE], M1.[NON-FAC PE RVU], M1.[WORK RVU], M1.[MP RVU], M1.[MULT PROC], m1.BILATSURG
		FROM [Analytics].[dbo].[MedicareFeeSchedule_Locality_1] M1
		WHERE M1.StartDate <= (Select TOP 1
				x.ServiceDateFrom
			FROM #Step1_Charges as x
			WHERE x.ProcedureCode = M1.HCPCS)
			and M1.EndDate >= (Select TOP 1
				x.ServiceDateFrom
			FROM #Step1_Charges as x
			WHERE x.ProcedureCode = M1.HCPCS)
	)
Select x.[EncounterID], [RevenueCode], [ProcedureCode], [ProcedureCodeNumeric], [Modifier1], x.[Sequence], y.[ServiceDateFrom], y.[ServiceDateTo], ISNULL(x.[ServiceDateFrom], y.[ServiceDateTo]) as [ServiceDate], [OriginalPayment], [Amount], [BillCharges], [Quantity], [Plan], [Payer01Code], [Payer01Name]


	, [OP_Default] = CASE
	WHEN 1=1 AND x.[ProcedureCode] NOT IN ('A4641', 'A4642', 'A9500', 'A9501','A9502', 'A9503', 'A9504', 'A9505','A9506', 'A9507', 'A9508', 'A9509','A9510', 'A9512', 'A9515', 'A9516','A9520', 'A9521', 'A9524', 'A9526','A9528', 'A9529', 'A9531', 'A9532','A9536', 'A9537', 'A9538', 'A9539','A9540', 'A9541', 'A9542', 'A9546','A9547', 'A9548', 'A9550', 'A9551','A9552', 'A9553', 'A9554', 'A9555','A9556', 'A9557', 'A9558', 'A9559','A9560', 'A9561', 'A9562', 'A9566','A9567', 'A9568', 'A9569', 'A9570','A9571', 'A9572', 'A9573', 'A9575','A9576', 'A9577', 'A9578', 'A9579','A9580', 'A9581', 'A9583', 'A9584','A9585', 'A9586', 'A9587', 'A9588','A9597', 'A9598', 'A9601', 'A9602','A9603', 'A9608', 'A9610', 'A9615','A9698', 'A9800', 'C9067', 'Q9951','Q9953', 'Q9954', 'Q9958','Q9959', 'Q9960', 'Q9961', 'Q9962','Q9963', 'Q9964','Q9965', 'Q9966', 'Q9967', 'Q9969','Q9982', 'Q9983','A4640', 'A4648', 'A4649', 'A9513','A9563', 'A9564', 'A9582', 'A9590','A9591', 'A9592', 'A9593', 'A9594','A9595', 'A9596', 'Q9950', 'Q9955','Q9956', 'Q9957', 'Q9968') THEN IIF(y.[ServiceDateFrom] < '2023-04-01', Round([Amount] * 0.79, 2), Round([Amount] * 0.782, 2))
	ELSE 0
	END



	, [ER] = CASE
	WHEN RevenueCode IN ('450','451','452','459') and (y.[ServiceDateFrom] between '2020-04-01' and '2021-03-31') THEN 1867	
	WHEN RevenueCode IN ('450','451','452','459') and (y.[ServiceDateFrom] between '2021-04-01' and '2022-03-31') THEN 2045
	WHEN RevenueCode IN ('450','451','452','459') and (y.[ServiceDateFrom] between '2022-04-01' and '2023-03-31') THEN 2239	
	WHEN RevenueCode IN ('450','451','452','459') and (y.[ServiceDateFrom] between '2023-04-01' and '2024-03-31') THEN 2340	
	WHEN RevenueCode IN ('450','451','452','459') and (y.[ServiceDateFrom] between '2024-04-01' and '2025-03-31') THEN 2468	
	WHEN RevenueCode IN ('450','451','452','459') and (y.[ServiceDateFrom] between '2025-04-01' and '2026-03-31') THEN 2616	
	
	WHEN RevenueCode IN ('456') and (y.[ServiceDateFrom] between '2020-04-01' and '2021-03-31') THEN  971
	WHEN RevenueCode IN ('456') and (y.[ServiceDateFrom] between '2021-04-01' and '2022-03-31') THEN 1063
	WHEN RevenueCode IN ('456') and (y.[ServiceDateFrom] between '2022-04-01' and '2023-03-31') THEN 1164	
	WHEN RevenueCode IN ('456') and (y.[ServiceDateFrom] between '2023-04-01' and '2024-03-31') THEN 1217	
	WHEN RevenueCode IN ('456') and (y.[ServiceDateFrom] between '2024-04-01' and '2025-03-31') THEN 1284	
	WHEN RevenueCode IN ('456') and (y.[ServiceDateFrom] between '2025-04-01' and '2026-03-31') THEN 1360	
	ELSE 0
	END



