	WHEN ((RevenueCode LIKE '36%') or (RevenueCode LIKE '49%') or (RevenueCode LIKE '75%') or (RevenueCode LIKE '79%') or (RevenueCode IN ('480','481')) AND ASCPT.[CPT] IS NOT NULL) and (y.[ServiceDateFrom] between '2020-04-01' and '2021-03-31') THEN  9287 		
	WHEN ((RevenueCode LIKE '36%') or (RevenueCode LIKE '49%') or (RevenueCode LIKE '75%') or (RevenueCode LIKE '79%') or (RevenueCode IN ('480','481')) AND ASCPT.[CPT] IS NOT NULL) and (y.[ServiceDateFrom] between '2021-04-01' and '2022-03-31') THEN 10169
	WHEN ((RevenueCode LIKE '36%') or (RevenueCode LIKE '49%') or (RevenueCode LIKE '75%') or (RevenueCode LIKE '79%') or (RevenueCode IN ('480','481')) AND ASCPT.[CPT] IS NOT NULL) and (y.[ServiceDateFrom] between '2022-04-01' and '2023-03-31') THEN 11135	
	WHEN ((RevenueCode LIKE '36%') or (RevenueCode LIKE '49%') or (RevenueCode LIKE '75%') or (RevenueCode LIKE '79%') or (RevenueCode IN ('480','481')) AND ASCPT.[CPT] IS NOT NULL) and (y.[ServiceDateFrom] between '2023-04-01' and '2024-03-31') THEN 11636
	WHEN ((RevenueCode LIKE '36%') or (RevenueCode LIKE '49%') or (RevenueCode LIKE '75%') or (RevenueCode LIKE '79%') or (RevenueCode IN ('480','481')) AND ASCPT.[CPT] IS NOT NULL) and (y.[ServiceDateFrom] between '2024-04-01' and '2025-03-31') THEN 12276
	WHEN ((RevenueCode LIKE '36%') or (RevenueCode LIKE '49%') or (RevenueCode LIKE '75%') or (RevenueCode LIKE '79%') or (RevenueCode IN ('480','481')) AND ASCPT.[CPT] IS NOT NULL) and (y.[ServiceDateFrom] between '2025-04-01' and '2026-03-31') THEN 13013
	ELSE 0
	END

	

