Into #Step2
From #Step1_Charges as x

	LEFT JOIN [COL].[Data].[Demo] as y on x.[EncounterID] = y.[EncounterID]
	LEFT JOIN [COL].[Data].[Dx_Px]	as dp on x.[EncounterID] = dp.[EncounterID] and x.[Sequence] = dp.[Sequence]
	LEFT JOIN [QNS].[FSG].[Aetna_Market_Fee_Schedule_January_2019_March_2021]	as AMFS_19_21 ON AMFS_19_21.[Proc_CD] = x.[ProcedureCode] and (y.[ServiceDateFrom] between AMFS_19_21.[StartDate] AND AMFS_19_21.[EndDate])
	LEFT JOIN [QNS].[FSG].[Aetna_Market_Fee_Schedule_January_2019_March_2021]	as AMFS_21_21 ON AMFS_21_21.[Proc_CD] = x.[ProcedureCode] and AMFS_21_21.[StartDate] = '2021-01-01 00:00:00.0000000'
	LEFT JOIN [QNS].[FSG].[Aetna_Market_Fee_Schedule_January_2022_March_2022]	as AMFS_22_22 ON AMFS_22_22.[Proc_CD] = x.[ProcedureCode]
	LEFT JOIN [QNS].[FSG].[Aetna_Market_Fee_Schedule_April_2022_March_2023]		as AMFS_22_23 ON AMFS_22_23.[Proc_CD] = x.[ProcedureCode]
	LEFT JOIN [QNS].[FSG].[Aetna_Market_Fee_Schedule_January_2023]				as AMFS_01_23 ON AMFS_01_23.[Proc_CD] = x.[ProcedureCode]
	LEFT JOIN [QNS].[dbo].[Aetna_Market_Fee_Schedule_September_2023]			as AMFS_23_23 ON AMFS_23_23.[Proc_CD] = x.[ProcedureCode]
	LEFT JOIN [QNS].[FSG].[Aetna_Market_Fee_Schedule_March_2024]				as AMFS_24 ON AMFS_24.[Proc_CD] = x.[ProcedureCode]
	LEFT JOIN [Analytics].[FSG].[Aetna_Market_FS_(2023-2025)]					AS AMFS ON AMFS.[CPT] = x.ProcedureCode AND y.ServiceDateFrom BETWEEN AMFS.StartDate and AMFS.EndDate

	LEFT JOIN [Analytics].[FSG].[Aetna_Drugs_CPTs]								AS D ON D.[CPT] = x.[ProcedureCode]
	LEFT JOIN [Analytics].[dbo].[Medicare Lab Fee Schedule]						as LAB1 ON LAB1.[HCPCS] = x.[ProcedureCode] and x.ServiceDateFrom between LAB1.[StartDate] AND LAB1.[EndDate] AND LAB1.[MOD] IS NULL
	LEFT JOIN [Analytics].[dbo].[MAC-Covid-19-Testing]							as COV on COV.[CPT_Code] = x.[ProcedureCode]
	LEFT JOIN [Analytics].[FSG].[Aetna_AS_List]									AS ASCPT ON ASCPT.[CPT] = x.[ProcedureCode]

	LEFT JOIN (
		SELECT
		[HCPCS], [MOD], [StartDate], [EndDate], [Rate], [NON-FAC PE RVU], [WORK RVU], [MP RVU], [MULT PROC], [BILATSURG],
		ROW_NUMBER() OVER (PARTITION BY [HCPCS] order by CASE
							WHEN [Mod] = 'TC' THEN 1
							WHEN [Mod] IN ('26','53') THEN 2
							ELSE 3
							END) AS row_num
	FROM CTE
		) M1
	ON x.procedureCode = M1.[HCPCS] and M1.row_num = 1

ORDER BY [EncounterID], x.[Sequence]


--***********************************************************************************************************************************************************************************************************************************************************************************************************

Select [EncounterID], [ServiceDate]	, [RevenueCode]	, [ProcedureCode]	, [Amount]	, [Quantity]	, [Sequence]	

	, [OP_Default]		= IIF([ER]=0 and [AS]=0 and [Minor_Surgery]=0 and [Endoscopy]=0 and [Laparoscopy]=0 and [Cardiac_Cath]=0 and [PTCA]=0 and [Vascular_Angioplasty]=0 and [Cardiac_Services]=0 and [Lithotripsy]=0 and [Gamma_Knife]=0 and [Hip_Knee_Replacement]=0 and [Shoulder_Replacement]=0 and [Implants]=0 and [Blood]=0 and [Blood_Processing]=0 and [Drugs]=0 and [Chemotherapy]=0 and [Lab]=0 and [Radiology/MRI/CT_Scan_Reduction]=0 and [Radiology/MRI/CT_Scan_NoReduction]= 0 and [Radiation_Therapy]=0 and [PT/OT/ST]=0  and [MRI/CT_noReduction]=0 and [MRI/CT_Reduction]=0 and [IOP]=0 and [Psych]=0 and [ECT]=0 and [Miscellaneous]=0 and [Sleep_Studies]=0 and [Clinic]=0, [OP_Default], 0)
	, [ER]
	, [AS]				
	, [Minor_Surgery]
	, [Endoscopy]
	, [Laparoscopy]
	, [Cardiac_Cath]
	, [Cardiac_Cath_Injection]
	, [PTCA]
	, [Vascular_Angioplasty]
	, [Cardiac_Services]
	, [Lithotripsy]
	, [Lithotripsy_Injection]
	, [Gamma_Knife]
	, [Hip_Knee_Replacement]
	, [Shoulder_Replacement]
	, [Implants]
	, [Blood]
	, [Blood_Processing]
	, [Drugs]	=IIF((modifier1 not in ('FB','SL') or Modifier1 IS NULL),[Drugs],0)
	, [Chemotherapy]
	, [Lab]
	, [ER_Check]

--	,[Radiology]
	, LEAD([Radiology/MRI/CT_Scan_Reduction]/1, 0, 0) over (partition by [EncounterID] order by [Radiology/MRI/CT_Scan_Reduction] desc, [Radiology/MRI/CT_Scan_Reduction] Desc) AS RD1
	, LEAD([Radiology/MRI/CT_Scan_Reduction]/2, 1, 0) over (partition by [EncounterID] order by [Radiology/MRI/CT_Scan_Reduction] desc, [Radiology/MRI/CT_Scan_Reduction] Desc) AS RD2
	, LEAD([Radiology/MRI/CT_Scan_Reduction]/2, 2, 0) over (partition by [EncounterID] order by [Radiology/MRI/CT_Scan_Reduction] desc, [Radiology/MRI/CT_Scan_Reduction] Desc) AS RD3
	, LEAD([Radiology/MRI/CT_Scan_Reduction]/2, 3, 0) over (partition by [EncounterID] order by [Radiology/MRI/CT_Scan_Reduction] desc, [Radiology/MRI/CT_Scan_Reduction] Desc) AS RD4
	, LEAD([Radiology/MRI/CT_Scan_Reduction]/2, 4, 0) over (partition by [EncounterID] order by [Radiology/MRI/CT_Scan_Reduction] desc, [Radiology/MRI/CT_Scan_Reduction] Desc) AS RD5
	, LEAD([Radiology/MRI/CT_Scan_Reduction]/2, 5, 0) over (partition by [EncounterID] order by [Radiology/MRI/CT_Scan_Reduction] desc, [Radiology/MRI/CT_Scan_Reduction] Desc) AS RD6
	, LEAD([Radiology/MRI/CT_Scan_Reduction]/2, 6, 0) over (partition by [EncounterID] order by [Radiology/MRI/CT_Scan_Reduction] desc, [Radiology/MRI/CT_Scan_Reduction] Desc) AS RD7
	, LEAD([Radiology/MRI/CT_Scan_Reduction]/2, 7, 0) over (partition by [EncounterID] order by [Radiology/MRI/CT_Scan_Reduction] desc, [Radiology/MRI/CT_Scan_Reduction] Desc) AS RD8
	, LEAD([Radiology/MRI/CT_Scan_Reduction]/2, 8, 0) over (partition by [EncounterID] order by [Radiology/MRI/CT_Scan_Reduction] desc, [Radiology/MRI/CT_Scan_Reduction] Desc) AS RD9
	, LEAD([Radiology/MRI/CT_Scan_Reduction]/2, 9, 0) over (partition by [EncounterID] order by [Radiology/MRI/CT_Scan_Reduction] desc, [Radiology/MRI/CT_Scan_Reduction] Desc) AS RD10

	, [Radiology/MRI/CT_Scan_NoReduction]

	, LEAD([MRI/CT_Reduction]/1, 0, 0) over (partition by [EncounterID] order by [MRI/CT_Reduction] desc, [MRI/CT_Reduction] Desc) AS RDC1
	, LEAD([MRI/CT_Reduction]/2, 1, 0) over (partition by [EncounterID] order by [MRI/CT_Reduction] desc, [MRI/CT_Reduction] Desc) AS RDC2
	, LEAD([MRI/CT_Reduction]/2, 2, 0) over (partition by [EncounterID] order by [MRI/CT_Reduction] desc, [MRI/CT_Reduction] Desc) AS RDC3
	, LEAD([MRI/CT_Reduction]/2, 3, 0) over (partition by [EncounterID] order by [MRI/CT_Reduction] desc, [MRI/CT_Reduction] Desc) AS RDC4
	, LEAD([MRI/CT_Reduction]/2, 4, 0) over (partition by [EncounterID] order by [MRI/CT_Reduction] desc, [MRI/CT_Reduction] Desc) AS RDC5
	, LEAD([MRI/CT_Reduction]/2, 5, 0) over (partition by [EncounterID] order by [MRI/CT_Reduction] desc, [MRI/CT_Reduction] Desc) AS RDC6
	, LEAD([MRI/CT_Reduction]/2, 6, 0) over (partition by [EncounterID] order by [MRI/CT_Reduction] desc, [MRI/CT_Reduction] Desc) AS RDC7
	, LEAD([MRI/CT_Reduction]/2, 7, 0) over (partition by [EncounterID] order by [MRI/CT_Reduction] desc, [MRI/CT_Reduction] Desc) AS RDC8
	, LEAD([MRI/CT_Reduction]/2, 8, 0) over (partition by [EncounterID] order by [MRI/CT_Reduction] desc, [MRI/CT_Reduction] Desc) AS RDC9
	, LEAD([MRI/CT_Reduction]/2, 9, 0) over (partition by [EncounterID] order by [MRI/CT_Reduction] desc, [MRI/CT_Reduction] Desc) AS RDC10


	, [MRI/CT_noReduction]


	, [Radiation_Therapy]

	, LEAD([PT/OT/ST], 0, 0) over (partition by [EncounterID] order by [PT/OT/ST] desc, [PT/OT/ST] Desc) AS Therapy1
	, LEAD([Therapy_MP] * [PT/OT/ST], 1, 0) over (partition by [EncounterID] order by [PT/OT/ST] desc, [PT/OT/ST] Desc) AS Therapy2
	, LEAD([Therapy_MP] * [PT/OT/ST], 2, 0) over (partition by [EncounterID] order by [PT/OT/ST] desc, [PT/OT/ST] Desc) AS Therapy3
	, LEAD([Therapy_MP] * [PT/OT/ST], 3, 0) over (partition by [EncounterID] order by [PT/OT/ST] desc, [PT/OT/ST] Desc) AS Therapy4
	, LEAD([Therapy_MP] * [PT/OT/ST], 4, 0) over (partition by [EncounterID] order by [PT/OT/ST] desc, [PT/OT/ST] Desc) AS Therapy5
	, LEAD([Therapy_MP] * [PT/OT/ST], 5, 0) over (partition by [EncounterID] order by [PT/OT/ST] desc, [PT/OT/ST] Desc) AS Therapy6
	, LEAD([Therapy_MP] * [PT/OT/ST], 6, 0) over (partition by [EncounterID] order by [PT/OT/ST] desc, [PT/OT/ST] Desc) AS Therapy7
	, LEAD([Therapy_MP] * [PT/OT/ST], 7, 0) over (partition by [EncounterID] order by [PT/OT/ST] desc, [PT/OT/ST] Desc) AS Therapy8
	, LEAD([Therapy_MP] * [PT/OT/ST], 8, 0) over (partition by [EncounterID] order by [PT/OT/ST] desc, [PT/OT/ST] Desc) AS Therapy9
	, LEAD([Therapy_MP] * [PT/OT/ST], 9, 0) over (partition by [EncounterID] order by [PT/OT/ST] desc, [PT/OT/ST] Desc) AS Therapy10


	, [IOP]
	, [Psych]
	, [ECT]
	, [Miscellaneous]
	, [Sleep_Studies]
	, [Clinic]			= IIF([Miscellaneous]=0, [Clinic], 0)
	, [COVID]


INTO #Step3
FROM #Step2

--***********************************************************************************************************************************************************************************************************************************************************************************************************
SELECT s.*
        , CAST(0 AS TINYINT) AS NeedsCorrectedClaim
INTO #Step3Bundle
FROM #Step3 s;


/* 
    Modifier = '0' - bundled
    Modifier = '1' - should pay, but needs mod 59/XE/XP/XS/XU 
    Modifier = '9' - always pays
    */

UPDATE b
    SET
        [OP_Default]                        = 0,
		RD1 =0,
		RD2 =0,
		RD3 =0,
		RD4 =0,
		RD5 =0,
		RD6 =0,
		RD7 =0,
		RD8 =0,
		RD9 =0,
		RD10 =0,
		RDC1 =0,
		RDC2 =0,
		RDC3 =0,
		RDC4 =0,
		RDC5 =0,
		RDC6 =0,
		RDC7 =0,
		RDC8 =0,
		RDC9 =0,
		RDC10 =0,
        [Lab]                       = 0
    FROM #Step3Bundle b
	JOIN #Step1_Charges c
	ON c.EncounterID   = b.EncounterID
		AND c.ProcedureCode = b.ProcedureCode
		AND c.Sequence      = b.Sequence
	JOIN [Analytics].[MCR_OPPS].[NCCI_CPT] n
	ON n.CPT = b.ProcedureCode
		AND b.ServiceDate >= n.Effective_Date
    WHERE n.Modifier = '0' and n.DeletionDate is null
	AND EXISTS (
            SELECT 1
	FROM #Step1_Charges p
	WHERE p.EncounterID   = b.EncounterID
		AND p.ProcedureCode = n.CPT_Parent
        );

UPDATE b
    SET NeedsCorrectedClaim = 1
    FROM #Step3Bundle b
	JOIN #Step1_Charges c
	ON c.EncounterID   = b.EncounterID
		AND c.ProcedureCode = b.ProcedureCode
		AND c.Sequence      = b.Sequence
	JOIN [Analytics].[MCR_OPPS].[NCCI_CPT] n
	ON n.CPT = b.ProcedureCode
		AND b.ServiceDate >= n.Effective_Date
        WHERE n.Modifier = '1'
	AND ISNULL(c.Modifier1,'') NOT IN ('59','XE','XP','XS','XU') AND n.DeletionDate is null
	AND EXISTS (
            SELECT 1
	FROM #Step1_Charges p
	WHERE p.EncounterID   = b.EncounterID
		AND p.ProcedureCode = n.CPT_Parent
      );

--***********************************************************************************************************************************************************************************************************************************************************************************************************

Select [EncounterID], [ServiceDate]

	, SUM([OP_Default])				as [OP_Default]
	, MAX([ER])						as [ER]
	, MAX([AS])						as [AS]
	, MAX([Minor_Surgery])			as [Minor_Surgery]
	, MAX([Endoscopy])				as [Endoscopy]	
	, MAX([Laparoscopy])				as [Laparoscopy]	
	, MAX([Cardiac_Cath])			as [Cardiac_Cath]
	, MAX([Cardiac_Cath_Injection])	as [Cardiac_Cath_Injection]
	, MAX([PTCA])					as [PTCA]
	, SUM([Vascular_Angioplasty])	as [Vascular_Angioplasty]
	, SUM([Cardiac_Services])		as [Cardiac_Services]
	, MAX([Lithotripsy])				as [Lithotripsy]
	, MAX([Lithotripsy_Injection])	as [Lithotripsy_Injection]	
	, MAX([Gamma_Knife])				as [Gamma_Knife]	
	, MAX([Hip_Knee_Replacement])	as [Hip_Knee_Replacement]
	, MAX([Shoulder_Replacement])	as [Shoulder_Replacement]
	, SUM([Implants])				as [Implants]
	, SUM([Blood])					as [Blood]
	, SUM([Blood_Processing])		as [Blood_Processing]
	, SUM([Drugs])					as [Drugs]
	, SUM([Chemotherapy])			as [Chemotherapy]
	, SUM([Lab])						as [Lab]
	, MAX(RD1)+MAX(RD2)+MAX(RD3)+MAX(RD4)+MAX(RD5)+MAX(RD6)+MAX(RD7)+MAX(RD8)+MAX(RD9)+MAX(RD10) 			AS [Radiology/MRI/CT_Scan_Reduction]
	, MAX(RDC1)+MAX(RDC2)+MAX(RDC3)+MAX(RDC4)+MAX(RDC5)+MAX(RDC6)+MAX(RDC7)+MAX(RDC8)+MAX(RDC9)+MAX(RDC10) 	AS [MRI/CT_Reduction]
	, SUM([Radiation_Therapy])		as [Radiation_Therapy]
	, MAX(Therapy1)+MAX(Therapy2)+MAX(Therapy3)+MAX(Therapy4)+MAX(Therapy5)+MAX(Therapy6)+MAX(Therapy7)+MAX(Therapy8)+MAX(Therapy9)+MAX(Therapy10) 	AS [PT/OT/ST]
	, SUM([IOP])						as [IOP]
	, SUM([Psych])					as [Psych]
	, SUM([ECT])						as [ECT]
	, SUM([Miscellaneous])			as [Miscellaneous]	
	, SUM([Sleep_Studies])			as [Sleep_Studies]
	, MAX([Clinic])					as [Clinic]
	, MAX([COVID])					as [COVID]
	, SUM([Radiology/MRI/CT_Scan_NoReduction])																AS [Radiology/MRI/CT_Scan_NoReduction]
	, SUM([MRI/CT_noReduction])																				AS [MRI/CT_noReduction]
	, MAX([ER_Check]) AS [ER_Check]
	, MAX(NeedsCorrectedClaim) AS NeedsCorrectedClaim

INTO #Step3_1
FROM #Step3Bundle

GROUP BY [EncounterID], [ServiceDate]

--***********************************************************************************************************************************************************************************************************************************************************************************************************
Select [EncounterID]

	, SUM([OP_Default])				as [OP_Default]
	, MAX([ER])						as [ER]
	, MAX([AS])						as [AS]
	, MAX([Minor_Surgery])			as [Minor_Surgery]
	, MAX([Endoscopy])				as [Endoscopy]	
	, MAX([Laparoscopy])				as [Laparoscopy]	
	, MAX([Cardiac_Cath])			as [Cardiac_Cath]
	, MAX([Cardiac_Cath_Injection])	as [Cardiac_Cath_Injection]
	, MAX([PTCA])					as [PTCA]
	, SUM([Vascular_Angioplasty])	as [Vascular_Angioplasty]
	, SUM([Cardiac_Services])		as [Cardiac_Services]
	, MAX([Lithotripsy])				as [Lithotripsy]
	, MAX([Lithotripsy_Injection])	as [Lithotripsy_Injection]		
	, MAX([Gamma_Knife])				as [Gamma_Knife]		
	, MAX([Hip_Knee_Replacement])	as [Hip_Knee_Replacement]
	, MAX([Shoulder_Replacement])	as [Shoulder_Replacement]
	, SUM([Implants])				as [Implants]
	, SUM([Blood])					as [Blood]
	, SUM([Blood_Processing])		as [Blood_Processing]
	, SUM([Drugs])					as [Drugs]
	, SUM([Chemotherapy])			as [Chemotherapy]	
	, SUM([Lab])						as [Lab]
	, SUM([Radiology/MRI/CT_Scan_Reduction])		AS [Radiology/MRI/CT_Scan_Reduction]
	, SUM([Radiology/MRI/CT_Scan_NoReduction])	AS [Radiology/MRI/CT_Scan_NoReduction]
	, SUM([MRI/CT_Reduction])					AS [MRI/CT_Reduction]	
	, SUM([Radiation_Therapy])		as [Radiation_Therapy]
	, SUM([PT/OT/ST])				as [PT/OT/ST]	
	, SUM([IOP])						as [IOP]
	, SUM([Psych])					as [Psych]
	, SUM([ECT])						as [ECT]
	, SUM([Miscellaneous])			as [Miscellaneous]
	, SUM([Sleep_Studies])			as [Sleep_Studies]
	, MAX([Clinic])					as [Clinic]	
	, MAX([COVID])					as [COVID]
	, SUM([MRI/CT_noReduction])					AS [MRI/CT_noReduction]
	, MAX([ER_Check]) 							AS [ER_Check]
	, MAX(NeedsCorrectedClaim) AS NeedsCorrectedClaim

INTO #Step3_2
FROM #Step3_1

GROUP BY EncounterID

--***********************************************************************************************************************************************************************************************************************************************************************************************************
Select [EncounterID]
	, [Drugs]					= IIF([Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Laparoscopy]!=0 or [Cardiac_Cath]!=0 or [AS]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [ER]!=0, 0, [Drugs])	 -- Auditor suggestions
	, [Implants]					= IIF([ER]!=0, 0, [Implants]) -- Auditor suggestions
	, [Blood]					= IIF([Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Laparoscopy]!=0 or [Cardiac_Cath]!=0 or [AS]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [ER]!=0, 0, [Blood])
	, [Blood_Processing]			= IIF([Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Laparoscopy]!=0 or [Cardiac_Cath]!=0 or [AS]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [ER]!=0, 0, [Blood_Processing])	
	, [Gamma_Knife]
	, [Shoulder_Replacement]		= IIF([Gamma_Knife]!=0, 0, [Shoulder_Replacement])
	, [Hip_Knee_Replacement]		= IIF([Gamma_Knife]!=0 or [Shoulder_Replacement]!=0, 0, [Hip_Knee_Replacement])
	, [PTCA]						= IIF([Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0, 0, [PTCA])
	, [Lithotripsy]				= IIF([Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0, 0, [Lithotripsy])
	, [Lithotripsy_Injection]	= IIF([Lithotripsy]!=0, [Lithotripsy_Injection], 0)
	, [Laparoscopy]				= IIF([Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0, 0, [Laparoscopy])
	, [Cardiac_Cath]				= IIF([Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Laparoscopy]!=0, 0, [Cardiac_Cath])
	, [Cardiac_Cath_Injection]	= IIF([Cardiac_Cath]!=0, [Cardiac_Cath_Injection], 0)
	, [Minor_Surgery]			= IIF([Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Laparoscopy]!=0 or [Cardiac_Cath]!=0, 0, [Minor_Surgery])
	, [Endoscopy]				= IIF([Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Laparoscopy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0, 0, [Endoscopy])
	, [AS]						= IIF([Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Laparoscopy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0, 0, [AS])	
	, [ER]						= IIF([Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Laparoscopy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [AS]!=0, 0, [ER])
	, [Psych]					= IIF([Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Laparoscopy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [AS]!=0 or [ER]!=0, 0, [Psych])
	, [ECT]						= IIF([Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Laparoscopy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [AS]!=0 or [ER]!=0 or [Psych]!=0, 0, [ECT])	
	, [IOP]						= IIF([Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Laparoscopy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [AS]!=0 or [ER]!=0 or [Psych]!=0, 0, [IOP])
	, [Vascular_Angioplasty]		= IIF([Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Laparoscopy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [AS]!=0 or [ER]!=0 or [Psych]!=0 or [ECT]!=0 or [IOP]!=0, 0, [Vascular_Angioplasty])
	, [Lab]						= IIF([Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Laparoscopy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [AS]!=0 or [ER]!=0 or [Psych]!=0 or [ECT]!=0 or [IOP]!=0, 0, [Lab])
	, [Radiation_Therapy]		= IIF([Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Laparoscopy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [AS]!=0 or [ER]!=0 or [Psych]!=0 or [ECT]!=0 or [IOP]!=0, 0, [Radiation_Therapy])
	, [PT/OT/ST]					= IIF([Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Laparoscopy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [AS]!=0 or [ER]!=0 or [Psych]!=0 or [ECT]!=0 or [IOP]!=0, 0, [PT/OT/ST])
	, [Cardiac_Services]			= IIF([Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Laparoscopy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [AS]!=0 or [ER]!=0 or [Psych]!=0 or [ECT]!=0 or [IOP]!=0, 0, [Cardiac_Services])
	, [Chemotherapy]				= IIF([Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Laparoscopy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [AS]!=0 or [ER]!=0 or [Psych]!=0 or [ECT]!=0 or [IOP]!=0, 0, [Chemotherapy])
	, [Sleep_Studies]			= IIF([Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Laparoscopy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [AS]!=0 or [ER]!=0 or [Psych]!=0 or [ECT]!=0 or [IOP]!=0, 0, [Sleep_Studies])
	, [Miscellaneous]			= IIF([Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Laparoscopy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [AS]!=0 or [ER]!=0 or [Psych]!=0 or [ECT]!=0 or [IOP]!=0, 0, [Miscellaneous])
	, [Clinic]					= IIF([Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Laparoscopy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [AS]!=0 or [ER]!=0 or [Psych]!=0 or [ECT]!=0 or [IOP]!=0, 0, [Clinic])			
	
	, [ER_Check]
	, [Radiology/MRI/CT_Scan_Reduction]		=IIF([Gamma_Knife]!=0 OR [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Laparoscopy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [AS]!=0 OR [Psych]!=0 or [ECT]!=0 or [Radiation_Therapy]!=0 OR [IOP]!=0 OR [ER_Check]=1, 0, [Radiology/MRI/CT_Scan_Reduction])
	, [MRI/CT_Reduction]						=IIF([Gamma_Knife]!=0 OR [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Laparoscopy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [AS]!=0 OR [Psych]!=0 or [ECT]!=0 or [Radiation_Therapy]!=0 OR [IOP]!=0 OR [ER_Check]!=1, 0, [MRI/CT_Reduction])
	, [Radiology/MRI/CT_Scan_NoReduction]	=IIF([Gamma_Knife]!=0 OR [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Laparoscopy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [AS]!=0 OR [Psych]!=0 or [ECT]!=0 or [Radiation_Therapy]!=0 OR [IOP]!=0 OR [ER_Check]=1, 0, [Radiology/MRI/CT_Scan_NoReduction])
	, [MRI/CT_noReduction]					=IIF([Gamma_Knife]!=0 OR [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Laparoscopy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [AS]!=0 OR [Psych]!=0 or [ECT]!=0 or [Radiation_Therapy]!=0 OR [IOP]!=0 OR [ER_Check]!=1, 0, [MRI/CT_noReduction])

	, [OP_Default]				= IIF( [Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Laparoscopy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [AS]!=0 or [ER]!=0 or [Psych]!=0 or [ECT]!=0 or [IOP]!=0  or [Cardiac_Services] != 0, 0, [OP_Default])		
	, [COVID]
	, [NeedsCorrectedClaim]

INTO #Step4
FROM #Step3_2;

--***********************************************************************************************************************************************************************************************************************************************************************************************************
-- *** [PRICE BREAKDOWN - INSERTED SECTION] ***
-- PURPOSE : Produce a LINE-LEVEL price breakdown for auditor review.
--           One row per charge line (EncounterID + Sequence + ProcedureCode).
--
-- SOURCE STRATEGY — CTE over #Step3Bundle, joined to #Step4:
--   #Step3Bundle  = line-level rows, post-NCCI bundling, pre-hierarchy
--   #Step4        = encounter-level, post-hierarchy suppression
--
--   MAX vs SUM categories (matching #Step3_1 aggregation logic):
--   MAX categories: only the single highest-value line per encounter pays.
--     ER, AS, Minor_Surgery, Endoscopy, Laparoscopy, Cardiac_Cath, Cardiac_Cath_Injection,
--     PTCA, Lithotripsy, Lithotripsy_Injection, Gamma_Knife, Hip_Knee_Replacement,
--     Shoulder_Replacement, Clinic
--   SUM categories: all matching lines pay.
--     OP_Default, Vascular_Angioplasty, Cardiac_Services, Implants, Blood, Blood_Processing,
--     Drugs, Chemotherapy, Lab, Radiation_Therapy, IOP, Psych, ECT, Miscellaneous,
--     Sleep_Studies, Radiology/MRI/CT (via LEAD windows), PT/OT/ST (via Therapy windows)
--
--   For MAX categories, ROW_NUMBER() ranks lines by category value DESC within each encounter.
--   Only rank = 1 (highest billed) receives LinePayment; lower-ranked lines show $0
--   and ServiceCategory suffix '_Non_Winner' so auditors can still see them.
--
--   ServiceCategory dual condition:
--     (a) b.[Category] > 0  — this line matched the category pattern
--     (b) s4.[Category] != 0 — the category survived #Step4 suppression for this encounter
--   A line that matched (a) but whose encounter had a higher-tier winner (b=0) is labeled
--   'Suppressed_By_Hierarchy'.
--
-- HIERARCHY (matches #Step4 IIF logic exactly):
--   1. Gamma_Knife   2. Shoulder_Replacement   3. Hip_Knee_Replacement   4. PTCA
--   5. Lithotripsy   6. Laparoscopy             7. Cardiac_Cath           8. Minor_Surgery
--   9. Endoscopy    10. AS (Ambulatory Surgery) 11. ER
--  12. Psych / ECT / IOP
--  13. Vascular_Angioplasty / Lab / Radiation_Therapy / PT/OT/ST / Cardiac_Services /
--      Chemotherapy / Sleep_Studies / Miscellaneous / Clinic
--  Special: Drugs/Blood/Blood_Processing suppressed by any surgical or ER category.
--           Implants suppressed only by ER.
--           Radiology/MRI/CT suppressed by ER_Check and surgical tiers per #Step4.
--           OP_Default suppressed if any named category (incl. Cardiac_Services) is non-zero.
--***********************************************************************************************************************************************************************************************************************************************************************************************************

-- #bRanked: temp table with all source columns plus ROW_NUMBER ranks for every
-- MAX category and every WINDOW_REDUCTION category.
-- Ties broken by Amount DESC, then Sequence ASC.
SELECT *
    SELECT *
        , ROW_NUMBER() OVER (PARTITION BY [EncounterID] ORDER BY [ER]                             DESC, [Amount] DESC, [Sequence] ASC) AS rn_ER
        , ROW_NUMBER() OVER (PARTITION BY [EncounterID] ORDER BY [AS]                             DESC, [Amount] DESC, [Sequence] ASC) AS rn_AS
        , ROW_NUMBER() OVER (PARTITION BY [EncounterID] ORDER BY [Minor_Surgery]                  DESC, [Amount] DESC, [Sequence] ASC) AS rn_MinorSurg
        , ROW_NUMBER() OVER (PARTITION BY [EncounterID] ORDER BY [Endoscopy]                      DESC, [Amount] DESC, [Sequence] ASC) AS rn_Endoscopy
        , ROW_NUMBER() OVER (PARTITION BY [EncounterID] ORDER BY [Laparoscopy]                    DESC, [Amount] DESC, [Sequence] ASC) AS rn_Laparoscopy
        , ROW_NUMBER() OVER (PARTITION BY [EncounterID] ORDER BY [Cardiac_Cath]                   DESC, [Amount] DESC, [Sequence] ASC) AS rn_CardiacCath
        , ROW_NUMBER() OVER (PARTITION BY [EncounterID] ORDER BY [Cardiac_Cath_Injection]         DESC, [Amount] DESC, [Sequence] ASC) AS rn_CCathInj
        , ROW_NUMBER() OVER (PARTITION BY [EncounterID] ORDER BY [PTCA]                           DESC, [Amount] DESC, [Sequence] ASC) AS rn_PTCA
        , ROW_NUMBER() OVER (PARTITION BY [EncounterID] ORDER BY [Lithotripsy]                    DESC, [Amount] DESC, [Sequence] ASC) AS rn_Lithotripsy
        , ROW_NUMBER() OVER (PARTITION BY [EncounterID] ORDER BY [Lithotripsy_Injection]          DESC, [Amount] DESC, [Sequence] ASC) AS rn_LithoInj
        , ROW_NUMBER() OVER (PARTITION BY [EncounterID] ORDER BY [Gamma_Knife]                    DESC, [Amount] DESC, [Sequence] ASC) AS rn_GammaKnife
        , ROW_NUMBER() OVER (PARTITION BY [EncounterID] ORDER BY [Hip_Knee_Replacement]           DESC, [Amount] DESC, [Sequence] ASC) AS rn_HipKnee
        , ROW_NUMBER() OVER (PARTITION BY [EncounterID] ORDER BY [Shoulder_Replacement]           DESC, [Amount] DESC, [Sequence] ASC) AS rn_Shoulder
        , ROW_NUMBER() OVER (PARTITION BY [EncounterID] ORDER BY [Clinic]                         DESC, [Amount] DESC, [Sequence] ASC) AS rn_Clinic
        -- Therapy: rank maps to LEAD slot — rank 1 pays Therapy1 (full rate), rank 2 pays Therapy2 (reduced), etc.
        -- ORDER BY Therapy1 DESC mirrors the original LEAD partition on [PT/OT/ST] DESC,
        -- since Therapy1 = LEAD([PT/OT/ST], 0) which is just the row's own PT/OT/ST value.
        , ROW_NUMBER() OVER (PARTITION BY [EncounterID] ORDER BY Therapy1                        DESC, [Amount] DESC, [Sequence] ASC) AS rn_Therapy
        -- Radiology: rank maps to RD slot. RD1 = LEAD([Radiology/...], 0) = row's own value.
        , ROW_NUMBER() OVER (PARTITION BY [EncounterID] ORDER BY RD1                             DESC, [Amount] DESC, [Sequence] ASC) AS rn_RD
        -- MRI/CT: rank maps to RDC slot. RDC1 = LEAD([MRI/CT_Reduction], 0) = row's own value.
        , ROW_NUMBER() OVER (PARTITION BY [EncounterID] ORDER BY RDC1                            DESC, [Amount] DESC, [Sequence] ASC) AS rn_RDC
INTO #bRanked
FROM #Step3Bundle;
-- #bSlots: one pivot row per encounter holding the rank-1 row's LEAD slot values.
-- Uses GROUP BY + MAX(CASE...) instead of WHERE rn=1 OR rn=1 to correctly handle
-- multiple window categories in a single pass without producing duplicate rows.
-- Each non-rank-1 row looks up its payment from the rank-1 row's corresponding slot
-- (rn_RD=2 gets rd.RD2, rn_RD=3 gets rd.RD3, etc.)

SELECT
    [EncounterID]
    -- Radiology/MRI/CT_Scan_Reduction slots (from rank-1 Radiology row)
    , MAX(CASE WHEN rn_RD  = 1 THEN RD1   ELSE 0 END) AS RD1
    , MAX(CASE WHEN rn_RD  = 1 THEN RD2   ELSE 0 END) AS RD2
    , MAX(CASE WHEN rn_RD  = 1 THEN RD3   ELSE 0 END) AS RD3
    , MAX(CASE WHEN rn_RD  = 1 THEN RD4   ELSE 0 END) AS RD4
    , MAX(CASE WHEN rn_RD  = 1 THEN RD5   ELSE 0 END) AS RD5
    , MAX(CASE WHEN rn_RD  = 1 THEN RD6   ELSE 0 END) AS RD6
    , MAX(CASE WHEN rn_RD  = 1 THEN RD7   ELSE 0 END) AS RD7
    , MAX(CASE WHEN rn_RD  = 1 THEN RD8   ELSE 0 END) AS RD8
    , MAX(CASE WHEN rn_RD  = 1 THEN RD9   ELSE 0 END) AS RD9
    , MAX(CASE WHEN rn_RD  = 1 THEN RD10  ELSE 0 END) AS RD10
    -- MRI/CT_Reduction slots (from rank-1 MRI/CT row)
    , MAX(CASE WHEN rn_RDC = 1 THEN RDC1  ELSE 0 END) AS RDC1
    , MAX(CASE WHEN rn_RDC = 1 THEN RDC2  ELSE 0 END) AS RDC2
    , MAX(CASE WHEN rn_RDC = 1 THEN RDC3  ELSE 0 END) AS RDC3
    , MAX(CASE WHEN rn_RDC = 1 THEN RDC4  ELSE 0 END) AS RDC4
    , MAX(CASE WHEN rn_RDC = 1 THEN RDC5  ELSE 0 END) AS RDC5
    , MAX(CASE WHEN rn_RDC = 1 THEN RDC6  ELSE 0 END) AS RDC6
    , MAX(CASE WHEN rn_RDC = 1 THEN RDC7  ELSE 0 END) AS RDC7
    , MAX(CASE WHEN rn_RDC = 1 THEN RDC8  ELSE 0 END) AS RDC8
    , MAX(CASE WHEN rn_RDC = 1 THEN RDC9  ELSE 0 END) AS RDC9
    , MAX(CASE WHEN rn_RDC = 1 THEN RDC10 ELSE 0 END) AS RDC10
    -- PT/OT/ST Therapy slots (from rank-1 Therapy row)
    , MAX(CASE WHEN rn_Therapy = 1 THEN Therapy1  ELSE 0 END) AS Therapy1
    , MAX(CASE WHEN rn_Therapy = 1 THEN Therapy2  ELSE 0 END) AS Therapy2
    , MAX(CASE WHEN rn_Therapy = 1 THEN Therapy3  ELSE 0 END) AS Therapy3
    , MAX(CASE WHEN rn_Therapy = 1 THEN Therapy4  ELSE 0 END) AS Therapy4
    , MAX(CASE WHEN rn_Therapy = 1 THEN Therapy5  ELSE 0 END) AS Therapy5
    , MAX(CASE WHEN rn_Therapy = 1 THEN Therapy6  ELSE 0 END) AS Therapy6
    , MAX(CASE WHEN rn_Therapy = 1 THEN Therapy7  ELSE 0 END) AS Therapy7
    , MAX(CASE WHEN rn_Therapy = 1 THEN Therapy8  ELSE 0 END) AS Therapy8
    , MAX(CASE WHEN rn_Therapy = 1 THEN Therapy9  ELSE 0 END) AS Therapy9
    , MAX(CASE WHEN rn_Therapy = 1 THEN Therapy10 ELSE 0 END) AS Therapy10
INTO #bSlots
FROM #bRanked
GROUP BY [EncounterID];

SELECT DISTINCT
    b.[EncounterID]
    , b.[Sequence]
    , b.[ProcedureCode]
    , b.[RevenueCode]
    , b.[ServiceDate]
    , b.[Amount]                                            AS [BilledAmount]
    , b.[Quantity]

    -- SERVICE CATEGORY:
    -- For MAX categories: appends '_Non_Winner' if this line matched but was not the highest-value line.
    --   These lines show LinePayment=$0 — the contract only pays the top line for MAX categories.
    -- For SUM categories: all matching lines that survived hierarchy are labeled normally.
    -- 'Suppressed_By_Hierarchy': line matched a category but a higher-tier category won for the encounter.
    , [ServiceCategory] = CASE
        WHEN s4.[Gamma_Knife]           != 0 AND b.[Gamma_Knife]           > 0 THEN IIF(b.rn_GammaKnife  = 1, 'Gamma_Knife',           'Gamma_Knife_Non_Winner')
        WHEN s4.[Shoulder_Replacement]  != 0 AND b.[Shoulder_Replacement]  > 0 THEN IIF(b.rn_Shoulder    = 1, 'Shoulder_Replacement',   'Shoulder_Replacement_Non_Winner')
        WHEN s4.[Hip_Knee_Replacement]  != 0 AND b.[Hip_Knee_Replacement]  > 0 THEN IIF(b.rn_HipKnee     = 1, 'Hip_Knee_Replacement',   'Hip_Knee_Replacement_Non_Winner')
        WHEN s4.[PTCA]                  != 0 AND b.[PTCA]                  > 0 THEN IIF(b.rn_PTCA         = 1, 'PTCA',                   'PTCA_Non_Winner')
        WHEN s4.[Lithotripsy]           != 0 AND b.[Lithotripsy]           > 0 THEN IIF(b.rn_Lithotripsy  = 1, 'Lithotripsy',            'Lithotripsy_Non_Winner')
        WHEN s4.[Laparoscopy]           != 0 AND b.[Laparoscopy]           > 0 THEN IIF(b.rn_Laparoscopy  = 1, 'Laparoscopy',            'Laparoscopy_Non_Winner')
        WHEN s4.[Cardiac_Cath]          != 0 AND b.[Cardiac_Cath]          > 0 THEN IIF(b.rn_CardiacCath  = 1, 'Cardiac_Cath',           'Cardiac_Cath_Non_Winner')
        WHEN s4.[Minor_Surgery]         != 0 AND b.[Minor_Surgery]         > 0 THEN IIF(b.rn_MinorSurg    = 1, 'Minor_Surgery',           'Minor_Surgery_Non_Winner')
        WHEN s4.[Endoscopy]             != 0 AND b.[Endoscopy]             > 0 THEN IIF(b.rn_Endoscopy    = 1, 'Endoscopy',               'Endoscopy_Non_Winner')
        WHEN s4.[AS]                    != 0 AND b.[AS]                    > 0 THEN IIF(b.rn_AS            = 1, 'Ambulatory_Surgery',      'Ambulatory_Surgery_Non_Winner')
        WHEN s4.[ER]                    != 0 AND b.[ER]                    > 0 THEN IIF(b.rn_ER            = 1, 'ER',                      'ER_Non_Winner')
        WHEN s4.[Cardiac_Cath_Injection] != 0 AND b.[Cardiac_Cath_Injection] > 0 THEN IIF(b.rn_CCathInj  = 1, 'Cardiac_Cath_Injection',  'Cardiac_Cath_Injection_Non_Winner')
        WHEN s4.[Lithotripsy_Injection] != 0 AND b.[Lithotripsy_Injection] > 0 THEN IIF(b.rn_LithoInj    = 1, 'Lithotripsy_Injection',   'Lithotripsy_Injection_Non_Winner')
        WHEN s4.[Clinic]                != 0 AND b.[Clinic]                > 0 THEN IIF(b.rn_Clinic        = 1, 'Clinic',                  'Clinic_Non_Winner')
        -- SUM categories — all matching lines pay, no winner/non-winner distinction
        WHEN s4.[Psych]                 != 0 AND b.[Psych]                 > 0 THEN 'Psych'
        WHEN s4.[ECT]                   != 0 AND b.[ECT]                   > 0 THEN 'ECT'
        WHEN s4.[IOP]                   != 0 AND b.[IOP]                   > 0 THEN 'IOP'
        WHEN s4.[Vascular_Angioplasty]  != 0 AND b.[Vascular_Angioplasty]  > 0 THEN 'Vascular_Angioplasty'
        WHEN s4.[Lab]                   != 0 AND b.[Lab]                   > 0 THEN 'Lab'
        WHEN s4.[Radiation_Therapy]     != 0 AND b.[Radiation_Therapy]     > 0 THEN 'Radiation_Therapy'
        WHEN s4.[PT/OT/ST]              != 0 AND (ISNULL(b.Therapy1,0)+ISNULL(b.Therapy2,0)+ISNULL(b.Therapy3,0)+ISNULL(b.Therapy4,0)+ISNULL(b.Therapy5,0)+ISNULL(b.Therapy6,0)+ISNULL(b.Therapy7,0)+ISNULL(b.Therapy8,0)+ISNULL(b.Therapy9,0)+ISNULL(b.Therapy10,0)) > 0 THEN 'PT_OT_ST'
        WHEN s4.[Cardiac_Services]      != 0 AND b.[Cardiac_Services]      > 0 THEN 'Cardiac_Services'
        WHEN s4.[Chemotherapy]          != 0 AND b.[Chemotherapy]          > 0 THEN 'Chemotherapy'
        WHEN s4.[Sleep_Studies]         != 0 AND b.[Sleep_Studies]         > 0 THEN 'Sleep_Studies'
        WHEN s4.[Miscellaneous]         != 0 AND b.[Miscellaneous]         > 0 THEN 'Miscellaneous'
        WHEN s4.[Drugs]                 != 0 AND b.[Drugs]                 > 0 THEN 'Drugs'
        WHEN s4.[Implants]              != 0 AND b.[Implants]              > 0 THEN 'Implants'
        WHEN s4.[Blood]                 != 0 AND b.[Blood]                 > 0 THEN 'Blood'
        WHEN s4.[Blood_Processing]      != 0 AND b.[Blood_Processing]      > 0 THEN 'Blood_Processing'
        WHEN (ISNULL(s4.[Radiology/MRI/CT_Scan_Reduction],0) + ISNULL(s4.[Radiology/MRI/CT_Scan_NoReduction],0)
            + ISNULL(s4.[MRI/CT_Reduction],0) + ISNULL(s4.[MRI/CT_noReduction],0)) != 0
          AND (ISNULL(b.RD1,0)+ISNULL(b.RD2,0)+ISNULL(b.RD3,0)+ISNULL(b.RD4,0)+ISNULL(b.RD5,0)
             + ISNULL(b.RD6,0)+ISNULL(b.RD7,0)+ISNULL(b.RD8,0)+ISNULL(b.RD9,0)+ISNULL(b.RD10,0)
             + ISNULL(b.[Radiology/MRI/CT_Scan_NoReduction],0)
             + ISNULL(b.RDC1,0)+ISNULL(b.RDC2,0)+ISNULL(b.RDC3,0)+ISNULL(b.RDC4,0)+ISNULL(b.RDC5,0)
             + ISNULL(b.RDC6,0)+ISNULL(b.RDC7,0)+ISNULL(b.RDC8,0)+ISNULL(b.RDC9,0)+ISNULL(b.RDC10,0)
             + ISNULL(b.[MRI/CT_noReduction],0)) > 0
            THEN CASE
                    -- NoReduction lines always pay in full (SUM category, all lines pay)
                    WHEN ISNULL(b.[Radiology/MRI/CT_Scan_NoReduction],0) > 0
                      OR ISNULL(b.[MRI/CT_noReduction],0) > 0               THEN 'Radiology_MRI_CT_NoReduction'
                    -- Reduction: each row pays its own slot from the rank-1 pivot row
                    -- rn_RD=1 gets RD1 (full rate), rn_RD=2 gets RD2 (50% reduced), etc.
                    WHEN b.rn_RD  BETWEEN 1 AND 10                           THEN 'Radiology_MRI_CT_Reduction'
                    WHEN b.rn_RDC BETWEEN 1 AND 10                           THEN 'MRI_CT_Reduction'
                    -- Beyond 10th slot — no payment
                    ELSE 'Radiology_MRI_CT_Beyond_Max'
                 END
        WHEN s4.[OP_Default]            != 0 AND b.[OP_Default]            > 0 THEN 'OP_Default'
        -- Line matched a category but #Step4 hierarchy zeroed it out for this encounter
        WHEN (ISNULL(b.[ER],0)+ISNULL(b.[AS],0)+ISNULL(b.[Minor_Surgery],0)+ISNULL(b.[Endoscopy],0)
            + ISNULL(b.[Laparoscopy],0)+ISNULL(b.[Cardiac_Cath],0)+ISNULL(b.[PTCA],0)
            + ISNULL(b.[Gamma_Knife],0)+ISNULL(b.[Hip_Knee_Replacement],0)+ISNULL(b.[Shoulder_Replacement],0)
            + ISNULL(b.[Lithotripsy],0)+ISNULL(b.[Vascular_Angioplasty],0)+ISNULL(b.[Cardiac_Services],0)
            + ISNULL(b.[Drugs],0)+ISNULL(b.[Implants],0)+ISNULL(b.[Blood],0)+ISNULL(b.[Blood_Processing],0)
            + ISNULL(b.[Chemotherapy],0)+ISNULL(b.[Lab],0)+ISNULL(b.[Radiation_Therapy],0)
            + ISNULL(b.Therapy1,0)+ISNULL(b.[IOP],0)+ISNULL(b.[Psych],0)+ISNULL(b.[ECT],0)
            + ISNULL(b.[Miscellaneous],0)+ISNULL(b.[Sleep_Studies],0)+ISNULL(b.[Clinic],0)
            + ISNULL(b.[OP_Default],0)
            + ISNULL(b.RD1,0)+ISNULL(b.RD2,0)+ISNULL(b.RD3,0)+ISNULL(b.RD4,0)+ISNULL(b.RD5,0)
            + ISNULL(b.RD6,0)+ISNULL(b.RD7,0)+ISNULL(b.RD8,0)+ISNULL(b.RD9,0)+ISNULL(b.RD10,0)
            + ISNULL(b.[Radiology/MRI/CT_Scan_NoReduction],0)
            + ISNULL(b.RDC1,0)+ISNULL(b.RDC2,0)+ISNULL(b.RDC3,0)+ISNULL(b.RDC4,0)+ISNULL(b.RDC5,0)
            + ISNULL(b.RDC6,0)+ISNULL(b.RDC7,0)+ISNULL(b.RDC8,0)+ISNULL(b.RDC9,0)+ISNULL(b.RDC10,0)
            + ISNULL(b.[MRI/CT_noReduction],0)) > 0                                 THEN 'Suppressed_By_Hierarchy'
        ELSE 'No_Payment_Category'
      END

    -- PRICING METHOD: how this line's category is reimbursed under the contract
    , [PricingMethod] = CASE
        WHEN s4.[Gamma_Knife]           != 0 AND b.[Gamma_Knife]           > 0 THEN 'Contracted flat rate per contract period (Gamma Knife CPT list: G0339/G0340/61796-61800/63620/63621)'
        WHEN s4.[Shoulder_Replacement]  != 0 AND b.[Shoulder_Replacement]  > 0 THEN 'Contracted flat rate per contract period (Shoulder CPT list: 23470/23472-23474)'
        WHEN s4.[Hip_Knee_Replacement]  != 0 AND b.[Hip_Knee_Replacement]  > 0 THEN 'Contracted flat rate per contract period (Hip/Knee CPT list: 27130/27132/27437-27447)'
        WHEN s4.[PTCA]                  != 0 AND b.[PTCA]                  > 0 THEN 'Contracted flat rate per contract period (PTCA CPT list: 92920-92944 / C9600-C9608)'
        WHEN s4.[Lithotripsy]           != 0 AND b.[Lithotripsy]           > 0 THEN 'Contracted flat rate per contract period (CPT 50590 only)'
        WHEN s4.[Laparoscopy]           != 0 AND b.[Laparoscopy]           > 0 THEN 'Contracted flat rate per contract period (Laparoscopy CPT list)'
        WHEN s4.[Cardiac_Cath]          != 0 AND b.[Cardiac_Cath]          > 0 THEN 'Contracted flat rate per contract period (Cardiac Cath CPT list: 93451-93592 and related)'
        WHEN s4.[Minor_Surgery]         != 0 AND b.[Minor_Surgery]         > 0 THEN 'Contracted flat rate per contract period (Minor Surgery CPT list)'
        WHEN s4.[Endoscopy]             != 0 AND b.[Endoscopy]             > 0 THEN 'Contracted flat rate per contract period (Endoscopy CPT ranges: 31615-31651 / 43191-43278 / 44360-44408 / 45300-45398)'
        WHEN s4.[AS]                    != 0 AND b.[AS]                    > 0 THEN 'Contracted flat rate per contract period (Ambulatory Surgery Rev 36x/49x/75x/79x/480/481 + Aetna AS CPT list)'
        WHEN s4.[ER]                    != 0 AND b.[ER]                    > 0 THEN 'Contracted flat rate per contract period (ER Rev 450/451/452/456/459)'
        WHEN s4.[Psych]                 != 0 AND b.[Psych]                 > 0 THEN 'Contracted per diem x Quantity (Rev 912/913)'
        WHEN s4.[ECT]                   != 0 AND b.[ECT]                   > 0 THEN 'Contracted flat rate x Quantity per contract period (Rev 901, CPT 90870)'
        WHEN s4.[IOP]                   != 0 AND b.[IOP]                   > 0 THEN 'Contracted per diem x Quantity (Rev 905/906)'
        WHEN s4.[Vascular_Angioplasty]  != 0 AND b.[Vascular_Angioplasty]  > 0 THEN 'Pct of charges: Amount x 78.2% (>=Apr-2023) or x79% (<Apr-2023) — CPT range 93880-93998'
        WHEN s4.[Lab]                   != 0 AND b.[Lab]                   > 0 THEN 'Medicare Lab Fee Schedule x period multiplier; fallback = COVID Lab Fee x multiplier'
        WHEN s4.[Radiation_Therapy]     != 0 AND b.[Radiation_Therapy]     > 0 THEN 'Pct of charges: Amount x 78.2% / 79% (Rev 331/332/333/335 and radiopharmaceutical CPTs)'
        WHEN s4.[PT/OT/ST]              != 0 AND (ISNULL(b.Therapy1,0)+ISNULL(b.Therapy2,0)+ISNULL(b.Therapy3,0)+ISNULL(b.Therapy4,0)+ISNULL(b.Therapy5,0)+ISNULL(b.Therapy6,0)+ISNULL(b.Therapy7,0)+ISNULL(b.Therapy8,0)+ISNULL(b.Therapy9,0)+ISNULL(b.Therapy10,0)) > 0 THEN 'Pct of charges x Multiple Procedure RVU reduction factor (97xxx range)'
        WHEN s4.[Cardiac_Services]      != 0 AND b.[Cardiac_Services]      > 0 THEN 'Pct of charges: Amount x 78.2% / 79% (CPT range 93000-93354 and listed cardiac codes)'
        WHEN s4.[Chemotherapy]          != 0 AND b.[Chemotherapy]          > 0 THEN 'Pct of charges: Amount x 78.2% / 79% (CPT 96401-96542, Q0083-Q0085)'
        WHEN s4.[Sleep_Studies]         != 0 AND b.[Sleep_Studies]         > 0 THEN 'Pct of charges: Amount x 78.2% / 79% (Sleep Study CPT list: 95782-95811 / G0398-G0400)'
        WHEN s4.[Miscellaneous]         != 0 AND b.[Miscellaneous]         > 0 THEN 'Contracted flat rate x Quantity OR pct-of-charges (Behavioral Health / Misc CPT list)'
        WHEN s4.[Clinic]                != 0 AND b.[Clinic]                > 0 THEN 'Rev 510-529 — $0 under current contract terms'
        WHEN s4.[Drugs]                 != 0 AND b.[Drugs]                 > 0 THEN 'Aetna Market Fee Schedule x period multiplier; fallback = Amount x 29% (Rev 634/635/636, J-codes; excl Modifier FB)'
        WHEN s4.[Implants]              != 0 AND b.[Implants]              > 0 THEN 'Pct of charges: Amount x 36% (Rev 274/275/276/278, excl device pass-through codes)'
        WHEN s4.[Blood]                 != 0 AND b.[Blood]                 > 0 THEN 'Pct of charges: Amount x 82% (Rev 380-389)'
        WHEN s4.[Blood_Processing]      != 0 AND b.[Blood_Processing]      > 0 THEN 'Pct of charges: Amount x 78.2% / 79% (Rev 390/391/399)'
        WHEN (ISNULL(s4.[Radiology/MRI/CT_Scan_Reduction],0) + ISNULL(s4.[Radiology/MRI/CT_Scan_NoReduction],0)
            + ISNULL(s4.[MRI/CT_Reduction],0) + ISNULL(s4.[MRI/CT_noReduction],0)) != 0
          AND (ISNULL(b.RD1,0)+ISNULL(b.RD2,0)+ISNULL(b.RD3,0)+ISNULL(b.RD4,0)+ISNULL(b.RD5,0)
             + ISNULL(b.RD6,0)+ISNULL(b.RD7,0)+ISNULL(b.RD8,0)+ISNULL(b.RD9,0)+ISNULL(b.RD10,0)
             + ISNULL(b.[Radiology/MRI/CT_Scan_NoReduction],0)
             + ISNULL(b.RDC1,0)+ISNULL(b.RDC2,0)+ISNULL(b.RDC3,0)+ISNULL(b.RDC4,0)+ISNULL(b.RDC5,0)
             + ISNULL(b.RDC6,0)+ISNULL(b.RDC7,0)+ISNULL(b.RDC8,0)+ISNULL(b.RDC9,0)+ISNULL(b.RDC10,0)
             + ISNULL(b.[MRI/CT_noReduction],0)) > 0
            THEN CASE
                        WHEN ISNULL(b.[Radiology/MRI/CT_Scan_NoReduction],0) > 0
                          OR ISNULL(b.[MRI/CT_noReduction],0) > 0  THEN 'Pct of charges: Amount x 78.2% — No multiple-procedure reduction applies'
                        WHEN b.rn_RD = 1 OR b.rn_RDC = 1          THEN 'Pct of charges: Amount x 78.2% — 1st procedure, full rate'
                        WHEN b.rn_RD BETWEEN 2 AND 10
                          OR b.rn_RDC BETWEEN 2 AND 10             THEN 'Pct of charges: Amount x 78.2% then x 50% — 2nd+ procedure reduction applies'
                        ELSE                                             'Beyond 10th procedure in encounter — $0 (outside reduction window)'
                     END
        WHEN s4.[OP_Default]            != 0 AND b.[OP_Default]            > 0 THEN 'Pct of charges: Amount x 78.2% (>=Apr-2023) or x79% (<Apr-2023) — OP Default catch-all'
        ELSE 'Category suppressed by encounter hierarchy or no pattern matched — $0'
      END

    -- LINE PAYMENT: contractual dollar amount for this specific charge line.
    -- MAX categories: IIF(rank=1, value, 0) — only the highest-value line per encounter pays.
    -- SUM categories: IIF(category survived in s4, value, 0) — all matching lines pay.
    , [LinePayment] = ROUND(
          IIF(s4.[ER]                  != 0, IIF(b.rn_ER          = 1, ISNULL(b.[ER], 0),                   0), 0)
        + IIF(s4.[AS]                  != 0, IIF(b.rn_AS          = 1, ISNULL(b.[AS], 0),                   0), 0)
        + IIF(s4.[Minor_Surgery]       != 0, IIF(b.rn_MinorSurg   = 1, ISNULL(b.[Minor_Surgery], 0),        0), 0)
        + IIF(s4.[Endoscopy]           != 0, IIF(b.rn_Endoscopy   = 1, ISNULL(b.[Endoscopy], 0),            0), 0)
        + IIF(s4.[Laparoscopy]         != 0, IIF(b.rn_Laparoscopy = 1, ISNULL(b.[Laparoscopy], 0),          0), 0)
        + IIF(s4.[PTCA]                != 0, IIF(b.rn_PTCA        = 1, ISNULL(b.[PTCA], 0),                 0), 0)
        + IIF(s4.[Cardiac_Cath]        != 0, IIF(b.rn_CardiacCath = 1, ISNULL(b.[Cardiac_Cath], 0),         0), 0)
        + IIF(s4.[Cardiac_Cath_Injection] != 0, IIF(b.rn_CCathInj = 1, ISNULL(b.[Cardiac_Cath_Injection], 0), 0), 0)
        + IIF(s4.[Lithotripsy]         != 0, IIF(b.rn_Lithotripsy = 1, ISNULL(b.[Lithotripsy], 0),          0), 0)
        + IIF(s4.[Lithotripsy_Injection] != 0, IIF(b.rn_LithoInj = 1, ISNULL(b.[Lithotripsy_Injection], 0), 0), 0)
        + IIF(s4.[Gamma_Knife]         != 0, IIF(b.rn_GammaKnife  = 1, ISNULL(b.[Gamma_Knife], 0),          0), 0)
        + IIF(s4.[Hip_Knee_Replacement] != 0, IIF(b.rn_HipKnee   = 1, ISNULL(b.[Hip_Knee_Replacement], 0), 0), 0)
        + IIF(s4.[Shoulder_Replacement] != 0, IIF(b.rn_Shoulder   = 1, ISNULL(b.[Shoulder_Replacement], 0), 0), 0)
        + IIF(s4.[Clinic]              != 0, IIF(b.rn_Clinic       = 1, ISNULL(b.[Clinic], 0),               0), 0)
        -- SUM categories — all matching lines pay
        + IIF(s4.[Vascular_Angioplasty]   != 0, ISNULL(b.[Vascular_Angioplasty], 0),                             0)
        + IIF(s4.[Cardiac_Services]       != 0, ISNULL(b.[Cardiac_Services], 0),                                  0)
        + IIF(s4.[Implants]               != 0, ISNULL(b.[Implants], 0),                                          0)
        + IIF(s4.[Blood]                  != 0, ISNULL(b.[Blood], 0),                                             0)
        + IIF(s4.[Blood_Processing]       != 0, ISNULL(b.[Blood_Processing], 0),                                  0)
        + IIF(s4.[Drugs]                  != 0, ISNULL(b.[Drugs], 0),                                             0)
        + IIF(s4.[Chemotherapy]           != 0, ISNULL(b.[Chemotherapy], 0),                                      0)
        + IIF(s4.[Lab]                    != 0, ISNULL(b.[Lab], 0),                                               0)
        + IIF(s4.[Radiation_Therapy]      != 0, ISNULL(b.[Radiation_Therapy], 0),                                 0)
        + IIF(s4.[PT/OT/ST]               != 0,
              CASE b.rn_Therapy
                WHEN 1  THEN ISNULL(rd.Therapy1,  0)
                WHEN 2  THEN ISNULL(rd.Therapy2,  0)
                WHEN 3  THEN ISNULL(rd.Therapy3,  0)
                WHEN 4  THEN ISNULL(rd.Therapy4,  0)
                WHEN 5  THEN ISNULL(rd.Therapy5,  0)
                WHEN 6  THEN ISNULL(rd.Therapy6,  0)
                WHEN 7  THEN ISNULL(rd.Therapy7,  0)
                WHEN 8  THEN ISNULL(rd.Therapy8,  0)
                WHEN 9  THEN ISNULL(rd.Therapy9,  0)
                WHEN 10 THEN ISNULL(rd.Therapy10, 0)
                ELSE 0
              END,                                                                                  0)
        + IIF(s4.[IOP]                    != 0, ISNULL(b.[IOP], 0),                                               0)
        + IIF(s4.[Psych]                  != 0, ISNULL(b.[Psych], 0),                                             0)
        + IIF(s4.[ECT]                    != 0, ISNULL(b.[ECT], 0),                                               0)
        + IIF(s4.[Sleep_Studies]          != 0, ISNULL(b.[Sleep_Studies], 0),                                     0)
        + IIF(s4.[Miscellaneous]          != 0, ISNULL(b.[Miscellaneous], 0),                                     0)
        + IIF(s4.[OP_Default]             != 0, ISNULL(b.[OP_Default], 0),                                        0)
        -- Radiology: b.rn_RD gives this row's rank; rd.RDn is the rank-1 pivot row's slot n.
        -- So rn_RD=1 gets rd.RD1, rn_RD=2 gets rd.RD2 (already halved), etc.
        + IIF(s4.[Radiology/MRI/CT_Scan_Reduction] != 0,
              CASE b.rn_RD
                WHEN 1  THEN ISNULL(rd.RD1,  0)
                WHEN 2  THEN ISNULL(rd.RD2,  0)
                WHEN 3  THEN ISNULL(rd.RD3,  0)
                WHEN 4  THEN ISNULL(rd.RD4,  0)
                WHEN 5  THEN ISNULL(rd.RD5,  0)
                WHEN 6  THEN ISNULL(rd.RD6,  0)
                WHEN 7  THEN ISNULL(rd.RD7,  0)
                WHEN 8  THEN ISNULL(rd.RD8,  0)
                WHEN 9  THEN ISNULL(rd.RD9,  0)
                WHEN 10 THEN ISNULL(rd.RD10, 0)
                ELSE 0
              END,                                                                                  0)
        + IIF(s4.[Radiology/MRI/CT_Scan_NoReduction] != 0, ISNULL(b.[Radiology/MRI/CT_Scan_NoReduction], 0),     0)
        -- MRI/CT: same pivot pattern via rd.RDCn.
        + IIF(s4.[MRI/CT_Reduction] != 0,
              CASE b.rn_RDC
                WHEN 1  THEN ISNULL(rd.RDC1,  0)
                WHEN 2  THEN ISNULL(rd.RDC2,  0)
                WHEN 3  THEN ISNULL(rd.RDC3,  0)
                WHEN 4  THEN ISNULL(rd.RDC4,  0)
                WHEN 5  THEN ISNULL(rd.RDC5,  0)
                WHEN 6  THEN ISNULL(rd.RDC6,  0)
                WHEN 7  THEN ISNULL(rd.RDC7,  0)
                WHEN 8  THEN ISNULL(rd.RDC8,  0)
                WHEN 9  THEN ISNULL(rd.RDC9,  0)
                WHEN 10 THEN ISNULL(rd.RDC10, 0)
                ELSE 0
              END,                                                                                  0)
        + IIF(s4.[MRI/CT_noReduction] != 0, ISNULL(b.[MRI/CT_noReduction], 0),                                   0)
      , 2)

    -- BUNDLED FLAG: 1 = this line was zeroed by NCCI bundling in #Step3Bundle
    , [BundledByNCCI]   = CAST(b.[NeedsCorrectedClaim] AS TINYINT)

INTO #LineBreakdown
FROM #bRanked b
INNER JOIN #Step4  s4 ON s4.[EncounterID] = b.[EncounterID]
LEFT  JOIN #bSlots rd ON rd.[EncounterID] = b.[EncounterID]
ORDER BY b.[EncounterID], b.[Sequence];

