--***********************************************************************************************************************************************************************************************************************************************************************************************************
-- *** [AUDITOR PRICE BREAKDOWN SUMMARY QUERIES - INSERTED SECTION] ***
-- Run these after the main script to get service-level breakdowns for review.
-- #LineBreakdown = one row per charge line (EncounterID + Sequence + ProcedureCode).
-- ServiceCategory reflects the final hierarchy decision from #Step4.
-- 'Suppressed_By_Hierarchy' = line matched a category but a higher-tier category won for the encounter.
--***********************************************************************************************************************************************************************************************************************************************************************************************************

-- QUERY 1: Full line-level detail for all claims.
-- One row per charge line. Use this to trace exactly how each CPT/Rev Code was categorized
-- and priced, and which lines were suppressed by the contract hierarchy or NCCI bundling.
SELECT
    lb.[EncounterID]
    , lb.[Sequence]
    , lb.[ProcedureCode]
    , lb.[RevenueCode]
    , lb.[ServiceDate]
    , lb.[BilledAmount]
    , lb.[Quantity]
    , lb.[ServiceCategory]
    , lb.[PricingMethod]
    , lb.[LinePayment]                                  AS [ContractualPayment_Line]
    , lb.[BundledByNCCI]                                AS [ZeroedByNCCI_Flag]
FROM #LineBreakdown lb
ORDER BY lb.[EncounterID], lb.[Sequence];


-- INSERT results into persistent table for cross-run analysis and reporting.
INSERT INTO [Automation].[dbo].[LineBreakdown_Results]
(EncounterID, Sequence, ProcedureCode, RevenueCode, ServiceDate,
 BilledAmount, Quantity, ServiceCategory, PricingMethod,
 LinePayment, BundledByNCCI, ScriptName, RunDate)
SELECT
    lb.[EncounterID]
    , lb.[Sequence]
    , lb.[ProcedureCode]
    , lb.[RevenueCode]
    , lb.[ServiceDate]
    , lb.[BilledAmount]
    , lb.[Quantity]
    , lb.[ServiceCategory]
    , lb.[PricingMethod]
    , lb.[LinePayment]
    , lb.[BundledByNCCI]
    , 'NYP_COL_AETNA_OP_COM'
    , GETDATE()
FROM #LineBreakdown lb
ORDER BY lb.[EncounterID], lb.[Sequence];


-- QUERY 2: Comparison analysis 

DROP TABLE IF EXISTS #temp;

select lb.[EncounterID], sum(lb.LinePayment) as FinalPrice
INTO #temp
FROM #LineBreakdown lb
group by lb.[EncounterID]


select  t.[EncounterID], t.FinalPrice, b.[Price], ( t.FinalPrice - b.[Price]) as diff
from #temp t
inner join #Step5 b
on t.[EncounterID] = b.[EncounterID]
where ( t.FinalPrice - b.[Price]) > 1 or ( t.FinalPrice - b.[Price]) < -1


